// AI-Powered Procurement Cost Analysis Engine
// Analyzes vendor pricing, contract terms, and market benchmarks
// to identify negotiation opportunities

const items = $input.all();

// Extract procurement data from combined inputs
const vendorData = items[0]?.json || {};
const contractTerms = items[1]?.json || {};
const invoiceHistory = items[2]?.json || {};
const marketBenchmarks = items[3]?.json || {};

// Initialize analysis results
const analysisResults = {
  timestamp: new Date().toISOString(),
  totalVendors: 0,
  negotiationOpportunities: [],
  costSavingsPotential: 0,
  riskFactors: [],
  recommendations: []
};

// Analyze pricing trends and identify outliers
function analyzePricingTrends(vendor, market) {
  const priceDifference = ((vendor.averagePrice - market.averagePrice) / market.averagePrice) * 100;
  const volumeDiscount = vendor.totalVolume > market.highVolumeThreshold ? 15 : 0;

  return {
    priceDifferencePercent: priceDifference,
    isAboveMarket: priceDifference > 5,
    potentialSavings: priceDifference > 0 ? (vendor.totalSpend * priceDifference / 100) : 0,
    volumeDiscountEligible: volumeDiscount > 0,
    negotiationScore: Math.min(100, priceDifference + volumeDiscount)
  };
}

// Evaluate contract renewal opportunities
function evaluateContractRenewal(contract) {
  const daysUntilExpiry = Math.floor((new Date(contract.expiryDate) - new Date()) / (1000 * 60 * 60 * 24));
  const isNearRenewal = daysUntilExpiry <= 90 && daysUntilExpiry > 0;

  return {
    daysUntilExpiry,
    isNearRenewal,
    renewalPriority: daysUntilExpiry <= 30 ? 'HIGH' : daysUntilExpiry <= 90 ? 'MEDIUM' : 'LOW',
    leverageOpportunity: isNearRenewal
  };
}

// Calculate payment term optimization
function analyzePaymentTerms(invoice, contract) {
  const currentTerms = contract.paymentTermsDays || 30;
  const industryStandard = 45;
  const earlyPaymentDiscount = invoice.earlyPaymentDiscountPercent || 0;

  return {
    currentTerms,
    industryStandard,
    termExtensionPotential: industryStandard - currentTerms,
    earlyPaymentDiscount,
    cashFlowImpact: (invoice.averageInvoiceAmount * (industryStandard - currentTerms)) / 365
  };
}

// Main analysis logic
if (vendorData.vendors && Array.isArray(vendorData.vendors)) {
  analysisResults.totalVendors = vendorData.vendors.length;

  vendorData.vendors.forEach(vendor => {
    // Pricing analysis
    const pricingAnalysis = analyzePricingTrends(
      vendor,
      marketBenchmarks[vendor.category] || {}
    );

    // Contract analysis
    const vendorContract = contractTerms.contracts?.find(c => c.vendorId === vendor.id) || {};
    const contractAnalysis = evaluateContractRenewal(vendorContract);

    // Payment terms analysis
    const vendorInvoices = invoiceHistory.invoices?.filter(i => i.vendorId === vendor.id) || [];
    const avgInvoice = vendorInvoices.reduce((sum, inv) => sum + (inv.amount || 0), 0) / (vendorInvoices.length || 1);
    const paymentAnalysis = analyzePaymentTerms(
      { averageInvoiceAmount: avgInvoice, earlyPaymentDiscountPercent: vendorContract.earlyPayDiscount },
      vendorContract
    );

    // Identify negotiation opportunities
    if (pricingAnalysis.negotiationScore > 20 || contractAnalysis.isNearRenewal) {
      const opportunity = {
        vendorId: vendor.id,
        vendorName: vendor.name,
        category: vendor.category,
        currentSpend: vendor.totalSpend,
        negotiationScore: pricingAnalysis.negotiationScore,
        opportunities: [],
        estimatedSavings: 0
      };

      // Price negotiation opportunity
      if (pricingAnalysis.isAboveMarket) {
        opportunity.opportunities.push({
          type: 'PRICE_REDUCTION',
          description: `Pricing ${pricingAnalysis.priceDifferencePercent.toFixed(1)}% above market average`,
          potentialSavings: pricingAnalysis.potentialSavings,
          priority: pricingAnalysis.priceDifferencePercent > 15 ? 'HIGH' : 'MEDIUM'
        });
        opportunity.estimatedSavings += pricingAnalysis.potentialSavings;
      }

      // Volume discount opportunity
      if (pricingAnalysis.volumeDiscountEligible) {
        const volumeSavings = vendor.totalSpend * 0.10;
        opportunity.opportunities.push({
          type: 'VOLUME_DISCOUNT',
          description: 'Eligible for volume-based pricing tier',
          potentialSavings: volumeSavings,
          priority: 'MEDIUM'
        });
        opportunity.estimatedSavings += volumeSavings;
      }

      // Contract renewal leverage
      if (contractAnalysis.isNearRenewal) {
        opportunity.opportunities.push({
          type: 'CONTRACT_RENEWAL',
          description: `Contract expires in ${contractAnalysis.daysUntilExpiry} days - negotiation window open`,
          potentialSavings: vendor.totalSpend * 0.08,
          priority: contractAnalysis.renewalPriority
        });
        opportunity.estimatedSavings += vendor.totalSpend * 0.08;
      }

      // Payment terms optimization
      if (paymentAnalysis.termExtensionPotential > 0) {
        opportunity.opportunities.push({
          type: 'PAYMENT_TERMS',
          description: `Extend payment terms from ${paymentAnalysis.currentTerms} to ${paymentAnalysis.industryStandard} days`,
          cashFlowBenefit: paymentAnalysis.cashFlowImpact,
          priority: 'LOW'
        });
      }

      analysisResults.negotiationOpportunities.push(opportunity);
      analysisResults.costSavingsPotential += opportunity.estimatedSavings;
    }
  });
}

// Generate AI-powered recommendations
analysisResults.recommendations = [
  {
    action: 'PRIORITIZE_HIGH_IMPACT',
    description: 'Focus on top 3 vendors with highest savings potential',
    targetVendors: analysisResults.negotiationOpportunities
      .sort((a, b) => b.estimatedSavings - a.estimatedSavings)
      .slice(0, 3)
      .map(v => v.vendorName)
  },
  {
    action: 'LEVERAGE_RENEWAL_TIMING',
    description: 'Initiate negotiations 60-90 days before contract expiry',
    affectedContracts: analysisResults.negotiationOpportunities
      .filter(o => o.opportunities.some(opp => opp.type === 'CONTRACT_RENEWAL'))
      .length
  },
  {
    action: 'BENCHMARK_COMPETITIVE_BIDS',
    description: 'Request competitive quotes for vendors pricing >10% above market',
    targetCategories: [...new Set(analysisResults.negotiationOpportunities
      .filter(o => o.opportunities.some(opp => opp.type === 'PRICE_REDUCTION'))
      .map(o => o.category))]
  }
];

// Risk assessment
if (analysisResults.negotiationOpportunities.length === 0) {
  analysisResults.riskFactors.push({
    type: 'NO_OPPORTUNITIES',
    severity: 'LOW',
    description: 'No immediate negotiation opportunities identified - pricing appears competitive'
  });
}

if (analysisResults.costSavingsPotential > 100000) {
  analysisResults.riskFactors.push({
    type: 'HIGH_SAVINGS_POTENTIAL',
    severity: 'MEDIUM',
    description: 'Significant savings identified - prioritize vendor negotiations this quarter'
  });
}

// Return opportunities array with proper structure for downstream processing
const outputOpportunities = analysisResults.negotiationOpportunities.map(opp => {
  const marketBenchmark = marketBenchmarks[opp.category] || {};
  const currentPrice = vendorData.vendors?.find(v => v.id === opp.vendorId)?.averagePrice || 0;
  const marketPrice = marketBenchmark.averagePrice || 0;
  const priceVariance = marketPrice > 0 ? ((currentPrice - marketPrice) / marketPrice * 100).toFixed(2) : 0;

  // Generate recommendation based on opportunities
  let recommendation = '';
  const highPriorityOpps = opp.opportunities.filter(o => o.priority === 'HIGH' || o.priority === 'CRITICAL');
  if (highPriorityOpps.length > 0) {
    recommendation = highPriorityOpps.map(o => o.description).join('; ');
  } else if (opp.opportunities.length > 0) {
    recommendation = opp.opportunities[0].description;
  } else {
    recommendation = 'Review vendor pricing and contract terms';
  }

  return {
    vendorName: opp.vendorName,
    savingsPotential: opp.estimatedSavings,
    currentPrice: currentPrice,
    marketPrice: marketPrice,
    priceVariance: priceVariance,
    recommendation: recommendation,
    category: opp.category,
    negotiationScore: opp.negotiationScore,
    opportunities: opp.opportunities
  };
});

return outputOpportunities.map(opp => ({ json: opp }));

